import numpy as np
# Value Iteration step
def value_iteration_step(V, P, R, gamma):
    Q = R + gamma * np.sum(P * V[np.newaxis, np.newaxis, :], axis=-1)
    return np.max(Q, axis=-1)

import torch

def ppo_clip_loss(log_probs, old_log_probs, advantages, eps=0.2):
    ratio = torch.exp(log_probs - old_log_probs)
    surr1 = ratio * advantages
    surr2 = torch.clamp(ratio, 1.0 - eps, 1.0 + eps) * advantages
    return -torch.mean(torch.min(surr1, surr2))

def dpo_loss(pi_logps_w, pi_logps_l, ref_logps_w, ref_logps_l, beta=0.1):
    # Implicit reward difference
    ratio_w = pi_logps_w - ref_logps_w
    ratio_l = pi_logps_l - ref_logps_l
    logits = beta * (ratio_w - ratio_l)
    return -torch.mean(torch.log(torch.sigmoid(logits)))

def bradley_terry_loss(chosen_rewards, rejected_rewards):
    # Train RM to maximize chosen response reward relative to rejected response reward
    return -torch.mean(torch.log(torch.sigmoid(chosen_rewards - rejected_rewards)))
